 *   2. Linked with toolchain's default hypot       (test_hypot_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

static inline uint64_t d2u(double d)
{
    union { double d; uint64_t u; } x;
    x.d = d;
    return x.u;
}

static inline double u2d(uint64_t u)
{
    union { double d; uint64_t u; } x;
    x.u = u;
    return x.d;
}

static void emit(double x, double y)
{
    double r = hypot(x, y);
    printf("%016llx %016llx %016llx\n",
           (unsigned long long)d2u(x),
           (unsigned long long)d2u(y),
           (unsigned long long)d2u(r));
}

static void emit_u(uint64_t bits_x, uint64_t bits_y)
{
    emit(u2d(bits_x), u2d(bits_y));
}

/* ------------------------------------------------------------------ */
/* Test points                                                         */
/* ------------------------------------------------------------------ */

/* 1. Special values */
static void test_special(void)
{
    /* Zeros */
    emit(0.0, 0.0);
    emit(-0.0, 0.0);
    emit(0.0, -0.0);

    /* NaN */
    emit_u(0x7ff8000000000000ULL, 0x3ff0000000000000ULL); /* qNaN, 1.0 */
    emit_u(0x3ff0000000000000ULL, 0x7ff8000000000000ULL); /* 1.0, qNaN */
    emit_u(0x7ff0000000000001ULL, 0x3ff0000000000000ULL); /* sNaN, 1.0 */

    /* Infinity */
    emit_u(0x7ff0000000000000ULL, 0x3ff0000000000000ULL); /* +Inf, 1.0 */
    emit_u(0xfff0000000000000ULL, 0x3ff0000000000000ULL); /* -Inf, 1.0 */
    emit_u(0x3ff0000000000000ULL, 0x7ff0000000000000ULL); /* 1.0, +Inf */
}

/* 2. Tiny values */
static void test_tiny(void)
{
    emit_u(0x0000000000000001ULL, 0x0000000000000001ULL); /* min denorm, min denorm */
    emit_u(0x0008000000000000ULL, 0x0008000000000000ULL); /* mid denorm, mid denorm */
    emit_u(0x000fffffffffffffULL, 0x000fffffffffffffULL); /* max denorm, max denorm */
    emit(DBL_MIN, DBL_MIN);
    emit(1.0e-150, 1.0e-150);
    emit(1.0e-100, 1.0e-100);
}

/* 3. Known mathematical values (Pythagorean triples) */
static void test_known(void)
{
    /* 3-4-5 triple */
    emit(3.0, 4.0);    /* sqrt(9+16) = 5 */
    emit(4.0, 3.0);    /* sqrt(16+9) = 5 (commutative) */

    /* 5-12-13 triple */
    emit(5.0, 12.0);   /* sqrt(25+144) = 13 */
    emit(12.0, 5.0);   /* sqrt(144+25) = 13 */

    /* 8-15-17 triple */
    emit(8.0, 15.0);   /* sqrt(64+225) = 17 */
    emit(15.0, 8.0);

    /* 7-24-25 triple */
    emit(7.0, 24.0);   /* sqrt(49+576) = 25 */
    emit(24.0, 7.0);

    /* 20-21-29 triple */
    emit(20.0, 21.0);  /* sqrt(400+441) = 29 */
    emit(21.0, 20.0);

    /* Special cases */
    emit(1.0, 0.0);    /* sqrt(1+0) = 1 */
    emit(0.0, 1.0);    /* sqrt(0+1) = 1 */
}

/* 4. Large arguments */
static void test_large(void)
{
    double vals[] = {
        1.0e10, 1.0e10,
        1.0e100, 1.0e100,
        1.0e150, 1.0e150,
        1.0e300, 1.0e300,
        DBL_MAX, 1.0,
    };
    int n = sizeof(vals) / sizeof(vals[0]);
    for (int i = 0; i < n - 1; i += 2)
        emit(vals[i], vals[i+1]);
}

/* 5. Magnitude variations */
static void test_magnitude_range(void)
{
    double bases[] = { 1.0, 10.0, 100.0, 1000.0 };
    int nbases = sizeof(bases) / sizeof(bases[0]);

    for (int i = 0; i < nbases; i++) {
        emit(bases[i], bases[i]);
        emit(bases[i], bases[i] * 2.0);
        emit(bases[i] * 2.0, bases[i]);
    }
}

/* 6. Worst-case rounding */
static void test_hard(void)
{
    double cases[][2] = {
        { 1.0, 1.0 },
        { 2.0, 2.0 },
        { 3.0, 4.0 },
        { 5.0, 12.0 },
        { u2d(0x3ff0000000000000ULL), u2d(0x3ff0000000000000ULL) }, /* 1.0, 1.0 */
        { u2d(0x4000000000000000ULL), u2d(0x4000000000000000ULL) }, /* 2.0, 2.0 */
    };
    int n = sizeof(cases) / sizeof(cases[0]);
    for (int i = 0; i < n; i++) {
        emit(cases[i][0], cases[i][1]);
        emit(-cases[i][0], cases[i][1]);
        emit(cases[i][0], -cases[i][1]);
    }
}

/* 7. Sweep both arguments [0, 10] */
static void test_sweep(void)
{
    int nsteps = 20;
    double hi = 10.0;
    double step = hi / (double)nsteps;

    for (int i = 0; i <= nsteps; i++) {
        for (int j = 0; j <= nsteps; j++) {
            emit((double)i * step, (double)j * step);
        }
    }
}

/* 8. Sample critical range with ULP granularity */
static void test_exhaustive_small(void)
{
    /* Both arguments in [1.0, 2.0] */
    uint64_t start = 0x3ff0000000000000ULL; /* 1.0 */
    uint64_t end = 0x4000000000000000ULL;   /* 2.0 */

    for (uint64_t x = start; x <= end; x += 140737488355328ULL)
        for (uint64_t y = start; y <= end; y += 140737488355328ULL)
            emit_u(x, y);
}

/* ------------------------------------------------------------------ */

int main(void)
{
    test_special();
    test_tiny();
    test_known();
    test_large();
    test_magnitude_range();
    test_hard();
    test_sweep();
    test_exhaustive_small();
    return 0;
}

